from typing import List
class Solution:
    def solve(self, c: List[int], freq: List[int], result: List[int]):
        i = 0
        j = 0
        while i < len(c):
            while j < len(freq) and c[i] != freq[j]:
                result.append(c[i])
                i += 1
            if j < len(freq):
                j += 1
            i += 1
        return result
