#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
void solve(vector<int>& c, vector<int>& freq, vector<int>& result) {
    int i = 0, j = 0;
    while (i < c.size()) {
        while (j < freq.size() && c[i] != freq[j]) {
            result.push_back(c[i]);
            i++;
        }
        if (j < freq.size()) {
            j++;
        }
        i++;
    }
}
};
int main() {
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<int> c(n), freq(n);
        for (int i = 0; i < n; i++)
            cin >> c[i];
        for (int i = 0; i < n; i++)
            cin >> freq[i];
        vector<int> result(n);
        Solution solution;
        solution.solve(c, freq, result);
        for (int i = 0; i < n; i++)
            cout << result[i] << ' ';
        cout << endl;
    }
    return 0;
}
